var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 기록보존실     \\n<color=#ffd34c>제 64 재난지구</color>     \\nCCTV 관련기록 편집 영상 #1","JPN":"管理局の記録保管室     \\n<color=#ffd34c>第64災害地区</color>     \\n監視カメラの関連記録編集映像#1","ENG":"[[","TWN":"管理局 檔案室     \\n<color=#ffd34c>第 64 災難地球</color>     \\nCCTV 相關記錄 編輯影像#1","THA":"ห้องเก็บบันทึกขององค์การบริหารโลก     \\n<color=#ffd34c>เขตภัยพิบัติที่ 64</color>     \\nวิดีโอจากกล้องวงจรปิดที่ถูกตัดต่อ #1","VTN":"Phòng Lưu Trữ Hồ Sơ Hành Chính     \\n<color=#ffd34c>Địa Hạt Tai Họa Thứ 64</color>     \\nHồ Sơ Video CCTV Đã Chỉnh Sửa #1","SCN":"管理局 档案室     \\n<color=#ffd34c>第 64 灾难地球</color>     \\n摄像 相关记录 编辑影像#1","DEU":"[[","FRA":"Salle des archives de l'Administration     \\n<color=#ffd34c>64e zone sinistrée</color>     \\nMontage de vidéosurveillance #1"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"콜록, 콜록......","JPN":"ゲホ、ゲホ……","ENG":"*Cough*, *Cough*","TWN":"咳咳，咳咳……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"벌써 일어났어? 좀 더 쉬라고 했잖아, 엄마.","JPN":"お母さん、もう起きたの？もっと寝ててもいいのに。","ENG":"You're up already? Mom, I told you to rest a bit more.","TWN":"妳已經起來了？我不是說要妳多休息一會了嗎，媽媽。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"일어나야지. 조금 있으면 식량배급표를 나눠 줄 시간이잖니?","JPN":"ううん。もう少しで、食料配給票を配る時間でしょ？","ENG":"I need to get up. They're going to hand out the food stamps soon.","TWN":"我得起來了。不是快要到發糧票的時間了嗎？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"그건 내가 알아서 한다니까?","JPN":"私がもらって来るから、気にしなくていいってば。","ENG":"I said I'll take care of that.","TWN":"那不是我去就好了嗎？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"몸도 성치 않은 사람이 자꾸 어딜 나가려고 그래?!","JPN":"お母さんは体が弱いから、出かけちゃダメ！","ENG":"Why do you keep trying to go outside when you're sick?","TWN":"身體不好的人，一直想著要出去幹什麼？！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"......엄마는 괜찮아. 너야말로 좀 더 자두렴.","JPN":"……お母さんは平気よ。あなたこそもっと寝なさい。","ENG":"I'm fine. You should be the one to get some more sleep.","TWN":"……媽媽沒事。倒是妳再睡會兒吧。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"구호소 난방도 시원치 않은데 감기 걸리겠다.","JPN":"救護所は暖房が弱いから、風邪をひいちゃうわ。","ENG":"The heating is terrible in the shelter. You'll catch a cold.","TWN":"救護所的暖氣也不太行，你會感冒的。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"아, 진짜! 감기는 무슨 감기야! 나 추위 안타는 거 몰라?","JPN":"もう！そんなわけないじゃん！私、寒さに強いの知ってるでしょ？","ENG":"Oh, come on! What cold? Don't you know that I never get cold?","TWN":"啊，真是的！感冒算什麼！妳不知道我不怕冷的嗎？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"엄마도 어렸을 때는 그런 줄 알았단다.","JPN":"お母さんも、若い頃はそう思ってたわ。","ENG":"I thought that too when I was young.","TWN":"媽媽小時候也是這樣認為的。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 매년 감기몸살을 달고 살았지.","JPN":"そのせいで、毎年風邪をひいたの。","ENG":"Which is why I always spent every winter with the flu.","TWN":"所以現在每年都會感冒。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"이리 오렴. 목도리 다시 감아 줄 테니까.","JPN":"こっちへ来なさい。マフラーを結び直してあげる。","ENG":"Come here. I'll fix your scarf again.","TWN":"來，我再給妳戴個圍巾。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"자, 다 됐다.","JPN":"はい、できたわよ。","ENG":"Okay, there.","TWN":"好了。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼 자리 잘 지키고 있어. 엄마는 금방 배급표 받아올게.","JPN":"じゃあ、ここで待っててね。すぐに配給票をもらって来るから。","ENG":"I'll be right back, you stay put. I'm going to go get the food stamps.","TWN":"那妳好好在這裡守著位子。媽媽馬上就拿完糧票了。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"엄마. 그러지 말고...... 나랑 같이 관리국에 가면 안돼?","JPN":"お母さん……私と一緒に、管理局に行くのじゃダメ？","ENG":"Mom. Instead of doing that... Can't you just go to the Administration with me?","TWN":"媽媽，別這麼說……妳不能跟我一起去管理局嗎？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"이거 봐! 나도 이젠 카운터라고!","JPN":"ほら！私もカウンターなんだよ！","ENG":"Look! I'm a Counter now!","TWN":"看這個！我已經是制裁者了！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};